const { randomUUID } = require('node:crypto');

module.exports = {
  addComment(projectId, taskId, commentData) {
    // Implement logic to add a comment to a task in a project
    // Return the added comment or null if there was an error
    return {
      id: randomUUID(),
      message: commentData.message,
      createdAt: new Date().toISOString()
    };
  }
};
